            sess
            for aid in publish.eligible_authid
            for sess in self._router._authid_to_sessions.get(aid, set())
        }
        receivers &= eligible

    # if "eligible_authrole" we only accept receivers that have the correct authrole
    if publish.eligible_authrole:
        eligible = {
            sess
            for ar in publish.eligible_authrole
            for sess in self._router._authrole_to_sessions.get(ar, set())
        }
        receivers &= eligible

    # remove "excluded" receivers
    if publish.exclude:
        # map excluded session IDs to excluded sessions using set comprehension
        exclude = {self._router._session_id_to_session[s] 
