def __new__(cls, clsname, bases, dct, **kwargs):
    coro_list = dct.get("coroutines", [])

    # Set comprehension to gather existing coroutines and threads in dct and bases
    existing_coros = {attr for attr in dct if attr.startswith("coro_") or attr.startswith("thread_")}

    # Extend coro_list from all base classes' "coroutines" and update existing_coros
    for b in bases:
        b_dct = b.__dict__
        coro_list.extend(b_dct.get("coroutines", []))
        existing_coros.update(
            {attr for attr in b_dct if attr.startswith("coro_") or attr.startswith("thread_")}
        )

    # Add _ExecutorMixin to bases
    if _ExecutorMixin not in bases:
        bases += (_ExecutorMixin,)

    # Add coro funcs to dct if not already provided by dct or bases
    for func in coro_list:
        coro_name = f"coro_{func}"
        if coro_name not in existing_coros:
            dct[coro_name] = cls.coro_maker(func)

    return super().__new__(cls, clsname, bases, dct)

