import re

def maketodo(pipfile, dbfile):
    # Read PIP file and store first word of each line in the set
    with open(pipfile, "r") as f:
        todos = {line.split()[0] for line in f}

    # Read dbfile and remove entries from the set based on first word
    with open(dbfile, "r") as f:
        todos -= {line.split()[0] for line in f}  # Set subtraction for removal from the set

    # Filter and print todos that do not match exclusion patterns or conditions
    for line in todos:
        if line.endswith(".VCC_WIRE"):
            continue
        if line.endswith(".GND_WIRE"):
            continue
        if re.match(r".*\.(L[HV]B?|G?CLK)(_L)?(_B)?[0-9]", line):
            continue
        if re.match(r"^INT_[LR]\.(CTRL|GFAN)(_L)?[0-9]", line):
            continue
        print(line)

